// menu.js - الكاردات أقرب إلى المنتصف
import { useState, useEffect } from "react";

export default function Menu() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [textIndex, setTextIndex] = useState(0);
  
  const backgroundImageUrl = "https://img.freepik.com/photos-premium/banniere-pour-page-menu-table-cuisine-legumes-epices-ustensiles-fond-sombre-vue-dessus-espace-libre-pour-texte_187166-66331.jpg?semt=ais_hybrid&w=740&q=80";
  
  const texts = ["مرحباً", "أهلاً", "تفضلوا", "استمتعوا"];

  // الكاردات - الآن أقرب إلى المنتصف
  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", size: 200, top: "15%", left: "10%", rotate: -6, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
    { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", size: 190, bottom: "15%", left: "12%", rotate: 4, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", size: 195, top: "18%", right: "10%", rotate: -4, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
    { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", size: 185, bottom: "18%", right: "12%", rotate: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" }
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setTextIndex((prev) => (prev + 1) % texts.length);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 40,
        y: (e.clientY / window.innerHeight - 0.5) * 40
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  const handleCardClick = (cardName) => {
    alert(`✨ لقد اخترت: ${cardName} ✨`);
  };

  return (
    <div style={{
      minHeight: "100vh",
      backgroundImage: `url(${backgroundImageUrl})`,
      backgroundSize: "cover",
      backgroundPosition: "center",
      backgroundRepeat: "no-repeat",
      backgroundAttachment: "fixed",
      position: "relative",
      overflow: "hidden",
      fontFamily: "sans-serif"
    }}>
      
      {/* الكاردات */}
      {cards.map((card) => (
        <div
          key={card.id}
          onClick={() => handleCardClick(card.name)}
          style={{
            position: "fixed",
            top: card.top,
            left: card.left,
            right: card.right,
            bottom: card.bottom,
            transform: `
              translate(
                ${mousePosition.x * (card.id % 2 === 0 ? 0.6 : -0.5)}px, 
                ${mousePosition.y * (card.id % 2 === 0 ? -0.5 : 0.6)}px
              ) 
              rotate(${card.rotate}deg)
            `,
            transition: "transform 0.2s ease-out",
            zIndex: 15,
            cursor: "pointer"
          }}
        >
          <div style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}cc)`,
            width: `${card.size}px`,
            padding: "30px 18px",
            borderRadius: "40px",
            textAlign: "center",
            boxShadow: "0 25px 50px rgba(0,0,0,0.5)",
            backdropFilter: "blur(8px)",
            border: "2px solid rgba(255,255,255,0.3)",
            transition: "all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = `scale(1.1) rotate(${card.rotate + 8}deg)`;
            e.currentTarget.style.boxShadow = "0 40px 70px rgba(0,0,0,0.6)";
            e.currentTarget.style.border = "2px solid rgba(34,197,94,0.9)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "scale(1) rotate(0deg)";
            e.currentTarget.style.boxShadow = "0 25px 50px rgba(0,0,0,0.5)";
            e.currentTarget.style.border = "2px solid rgba(255,255,255,0.3)";
          }}
          >
            <img 
              src={card.image} 
              alt={card.name} 
              style={{ 
                width: "85px", 
                height: "85px", 
                marginBottom: "12px", 
                filter: "drop-shadow(2px 4px 10px black)" 
              }} 
            />
            <h3 style={{ 
              color: "white", 
              margin: "10px 0 5px", 
              fontSize: "1.8rem", 
              fontWeight: "bold" 
            }}>{card.name}</h3>
            <span style={{ fontSize: "2.8rem" }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* كلمة MONO في المنتصف */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.15}px, ${mousePosition.y * 0.15}px)`,
        textAlign: "center",
        zIndex: 25,
        transition: "transform 0.15s ease-out",
        pointerEvents: "none"
      }}>
        <h1 style={{
          fontSize: "7rem",
          fontWeight: "900",
          color: "#22c55e",
          margin: 0,
          letterSpacing: "6px",
          textShadow: "0 0 30px rgba(34,197,94,0.8), 0 0 60px rgba(34,197,94,0.5)",
          whiteSpace: "nowrap"
        }}>
          {texts[textIndex]}
        </h1>
        <div style={{
          width: "120px",
          height: "4px",
          background: "linear-gradient(90deg, #22c55e, #4ade80, #22c55e)",
          margin: "25px auto 0",
          borderRadius: "10px"
        }}></div>
      </div>

      <div style={{
        position: "fixed",
        bottom: "20px",
        left: "50%",
        transform: "translateX(-50%)",
        textAlign: "center",
        color: "rgba(255,255,255,0.8)",
        fontSize: "13px",
        zIndex: 30,
        pointerEvents: "none",
        backgroundColor: "rgba(0,0,0,0.5)",
        padding: "6px 14px",
        borderRadius: "20px",
        whiteSpace: "nowrap"
      }}>
        ✨ اضغط على أي كارد لاختيار المنتج ✨
      </div>
    </div>
  );
}
